INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-003',
  'How to know your baby is getting enough',
  '"Is my baby getting enough?" is the most common question new moms have, and the answer lives in three places: diapers, weight, and behavior. Want me to walk you through exactly what to look for this week?',
  'The most reliable output markers in week one:

Diapers: By day 4–5, expect at least 6 wet diapers and 3–4 yellow seedy stools per 24 hours. Urine should be pale yellow — dark or brick-red (urate crystals) in the first 2–3 days is normal, but should clear by day 4.

Weight: It is normal for newborns to lose up to 7% of birth weight in the first 3–5 days. Most regain birth weight by days 10–14. Your pediatrician will track this at the 2-day and 2-week visits. If your baby has not regained birth weight by 2 weeks, a lactation evaluation is recommended.

Behavior: A well-fed baby will have periods of alertness and will release the breast or bottle spontaneously. A baby who seems constantly hungry, sleepy and hard to wake, or inconsolable after most feedings may not be transferring enough milk.

For pumping moms: pump output alone is not always a reliable indicator of what a baby would transfer directly. A baby typically extracts more efficiently than a pump in the early weeks. Sources: AAP 2022; ABM Protocol #3; LLLI "Is My Baby Getting Enough Milk?"',
  'Contact your pediatrician promptly if: baby has not regained birth weight by 2 weeks, has fewer than 6 wet diapers after day 5, is not waking to feed every 2–3 hours, or seems excessively yellow (jaundiced). These are the main reasons newborns are readmitted in the first 2 weeks.',
  NULL,
  'AAP 2022; ABM Protocol #3; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
