INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-005',
  'Get ready: the week 3 growth spurt is coming',
  'Around week 2–3, most babies hit their first major growth spurt. Your baby may seem like they want to eat constantly, act fussier than usual, and make you feel like your supply suddenly disappeared. It didn''t. Here''s what''s actually happening.',
  'Growth spurts are periods of accelerated developmental growth during which babies increase feeding frequency dramatically — sometimes nursing or feeding every 45–60 minutes for 24–48 hours. This behavior is called cluster feeding, and it''s biologically intentional: the baby is signaling your body to increase milk production to meet their growing needs. Common timing: around weeks 2–3, 6–8, and 10–12, with some variation.

What to do: follow the baby''s cues and feed on demand. Trying to space out feeds during a growth spurt to "save up" milk is counterproductive — it signals your body to produce less, not more. For pumping moms, you may need to add one or two pump sessions per day during the spurt. The increased demand is temporary — most cluster feeding phases last 2–4 days.

What this is not: a sign that you don''t have enough milk, that your milk isn''t satisfying enough, or that your baby needs formula. Growth spurts are often the moment families abandon breastfeeding when the real need is just more frequent feeding for a few days. Sources: LLLI "Growth Spurts"; ABM Protocol #2.',
  NULL,
  NULL,
  'LLLI; ABM Protocol #2',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
