INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-006',
  'Your supply is being established right now',
  'The first 4–6 weeks are when your body sets its long-term milk production baseline. What you do now — how often you feed or pump, and how completely your breasts are drained — is telling your body how much to make for the entire journey. This is worth understanding.',
  'Milk supply operates on a supply-and-demand system regulated by the hormone prolactin. In the early weeks, prolactin levels are high and the system is sensitive — frequent, thorough removal of milk sends a strong signal to maintain and increase production. Milk left in the breast signals production to slow. This is why frequent feeding in the first 4–6 weeks is so important: you''re not just feeding today''s baby, you''re calibrating tomorrow''s supply.

For nursing moms: aim for 8–12 feedings per 24 hours. Night feeds matter — prolactin levels are highest between midnight and 6am, so skipping night feeds in this window can meaningfully affect supply.

For pumping moms: the same principle applies. 8–10 pump sessions per 24 hours in weeks 1–6 establishes a higher baseline than fewer, longer sessions. Once supply is established (usually around weeks 6–10), many moms can reduce session frequency.

For combo feeding moms: every nursing session or pump session counts. You''re not in an either/or situation — every time milk is removed, your body gets the signal. Sources: ABM Protocol #2; ABM Protocol #9; Hale''s Medications and Mothers'' Milk; LLLI.',
  NULL,
  NULL,
  'ABM Protocol #2; ABM Protocol #9; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
  in_app_message        = EXCLUDED.in_app_message,
