INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-007',
  'Thinking about introducing a bottle? Timing and technique matter',
  'If you''re planning to introduce a bottle — so a partner can feed, or for returning to work — the window of weeks 3–6 is often recommended. Too early can interfere with latch; too late and some babies resist. There''s also a technique that protects your supply. Want to know more?',
  '"Nipple confusion" — where a baby prefers the bottle and resists the breast — is real but not universal. Bottles flow faster and with less effort than the breast, which can lead some babies to become frustrated with nursing. To reduce this risk:

Timing: most IBCLCs recommend waiting until breastfeeding is well established (usually 3–4 weeks) before introducing a bottle, though some families do it earlier without issue.

Paced bottle feeding: hold the bottle horizontal (not tilted up), let the baby draw the nipple in actively rather than tipping milk in, and allow pauses. This mimics the effort of nursing and slows intake so the baby doesn''t overfeed. Feed responsively — stop when the baby shows satiation cues, regardless of how much is left in the bottle.

For your supply: if you introduce a bottle and miss a nursing session, pump at that same time to maintain the feeding signal to your body.

Bottle nipple choice: slow-flow nipples are recommended for breastfed babies regardless of age, to avoid bottle preference from flow rate differences. Sources: ABM Protocol #2; ABM Protocol #10; LLLI "Introducing a Bottle."',
  NULL,
  NULL,
  'ABM Protocol #2; ABM Protocol #10; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
  in_app_message        = EXCLUDED.in_app_message,
