INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-008',
  'Your breasts may feel softer now — that''s a good sign',
  'Around week 6, many nursing moms notice their breasts feel less full, softer, and don''t seem to "fill up" the same way they used to. This alarms a lot of moms. It almost always means your supply is regulating, not disappearing. Here''s why.',
  'In the early weeks, breasts are producing milk somewhat continuously and often feel noticeably full between feeds. Around weeks 4–6 (timing varies), the supply system shifts: your body transitions from producing milk continuously to producing it more in response to feeding demand — a more efficient, on-demand system. This is called supply regulation.

What it feels like: breasts feel softer, less engorged between feeds, and milk may not spray or drip as noticeably. Some moms also stop feeling as strong a letdown sensation.

What it isn''t: supply dropping. The baby is still getting the same amount of milk — your body is just getting more efficient at producing it on the right schedule. If your baby has normal wet/dirty diapers, is gaining weight appropriately, and seems satisfied after most feeds, your supply is fine.

What to watch: if the softening is accompanied by a sudden change in baby''s weight gain, diaper output, or behavior at the breast, that''s worth checking with your pediatrician or IBCLC. But softness alone, in the context of a thriving baby, is reassuring. Sources: LLLI "Changes in Milk Production"; ABM Protocol #2.',
  NULL,
  NULL,
  'LLLI; ABM Protocol #2',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
