INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-010',
  'Sleep regression + feeding: what to expect',
  'Around 2 months, many babies who were starting to consolidate sleep suddenly start waking more again. This is normal neurological development — not a feeding problem, and not a supply problem. But it affects feeding. Here''s what''s happening.',
  'The 8–10 week period often involves a neurological leap that temporarily disrupts sleep patterns. Babies who were sleeping longer stretches may start waking more frequently at night. This is developmental and temporary — it''s not caused by hunger, insufficient milk, or anything you''re doing wrong.

For breastfeeding and pumping moms: the return of night waking can feel like a setback, but it''s also free supply protection — night feeds stimulate the high-prolactin window. If your baby is waking to feed and feeding well, follow their lead. If you''re pumping and your baby suddenly wants more in the middle of the night, add a session if possible.

For moms who were hoping to drop night feeds around this time: that''s a reasonable goal, but the 8–10 week window is often not the right moment. A few more weeks of patience here is usually the path of least resistance. Sources: AAP safe sleep guidelines; LLLI; published infant sleep development literature.',
  NULL,
  NULL,
  'AAP safe sleep guidelines; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
