INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-012',
  'Three months in — here''s what changes and what doesn''t',
  'Three months is a real milestone. Feeding typically gets easier and faster from here. Your body knows what it''s doing, your baby is more efficient, and the hardest adjustment period is behind you. Want to know what to expect in the next chapter?',
  'After 3 months, several things typically shift:

Feeding efficiency: babies become faster feeders — sessions that took 30–40 minutes in the early weeks often take 10–15 minutes by month 3. This is normal and not a sign of disinterest or reduced milk transfer.

Distraction: babies become more aware of their surroundings and may pop on and off frequently during feeds. Feeding in quieter environments or using a nursing cover can help for easily distracted babies.

Supply stability: for most moms, supply is well-calibrated by 3 months and is unlikely to drop dramatically without a significant change in feeding frequency. Continuing to feed or pump consistently protects supply going forward.

Solids reminder: the AAP recommends waiting until 6 months (26 weeks) to introduce solid foods for most babies — breast milk or formula should be the primary nutrition until that point. Introducing solids too early can reduce milk intake and supply.

Weaning eventually: when you''re ready, gradual weaning — dropping one feed every few days — is gentler on your body and your baby than stopping abruptly. Sources: AAP 2022; ABM Protocol #2; LLLI.',
  NULL,
  NULL,
  'AAP 2022; ABM Protocol #2; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
  in_app_message        = EXCLUDED.in_app_message,
