INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-013',
  'Returning to work soon? Let''s make a pumping plan',
  'Returning to work while breastfeeding or pumping is doable — but it goes better with a plan made before your first day back, not after. Want to walk through the key things to set up now?',
  'Key things to address before your first day back:

Build a freezer stash: start 2–3 weeks before return. Pump once per day after your first morning feed (when output is typically highest) to accumulate a buffer. You don''t need a huge stash — 3–5 days'' worth is a good working buffer.

Pump at work: under the PUMP Act (2022), most US employers must provide reasonable break time and a private space (not a bathroom) for pumping. Know your rights before you need them. Plan for pump sessions roughly every 3 hours during your work hours — this mirrors your baby''s feeding pattern and protects supply.

Pump bag and supplies: double-check that your pump is fully functional, you have enough flanges and backups for spare parts, and you have a cooler or access to refrigeration at work.

Timing and storage: freshly pumped milk keeps at room temperature for up to 4 hours, in the refrigerator for up to 4 days, and in the freezer for up to 6 months at 0°F. Label bags with date and time.

The first week back is often the hardest emotionally. Many moms feel anxious about supply. The best protection: pump consistently at work, nurse or pump on your normal schedule on non-work days, and give yourself a few weeks before drawing conclusions about supply. Sources: CDC human milk storage guidelines; US PUMP Act 2022; ABM Protocol #2.',
  NULL,
  NULL,
  'CDC milk storage guidelines; US PUMP Act 2022; ABM Protocol #2',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
  in_app_message        = EXCLUDED.in_app_message,
