INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-014',
  '2-week visit coming up — here''s what to ask about feeding',
  'Your baby''s 2-week visit is one of the most important feeding checkpoints. The pediatrician will weigh your baby and assess whether birth weight has been regained. Here''s what to ask so you get the most out of 10 minutes.',
  'Questions worth asking at the 2-week visit:

— Has my baby regained their birth weight? If not, by what date should I expect it, and what should I do in the meantime?
— Is the current diaper output normal for their age and feeding pattern?
— Is there anything in their latch or weight gain pattern that suggests I should see a lactation consultant?
— What weight gain rate should I expect over the next 4 weeks? (Typical: 5–7 oz/week in months 1–3)
— If you''re formula supplementing: is this amount appropriate, and how do I know when to reduce or stop?

Tip: bring a feeding log or share your Latched feeding data if you''ve been tracking. Pediatricians work faster and better with concrete data. Sources: AAP 2022; ABM Protocol #3.',
  'If your baby has not regained birth weight by the 2-week visit, ask specifically what the plan is and what threshold would prompt a lactation referral. Don''t leave without a clear timeline and follow-up plan.',
  NULL,
  'AAP 2022; ABM Protocol #3',
  NULL,
  NULL,
  NULL
