INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-015',
  '2-month visit: feeding questions worth bringing',
  'The 2-month visit is mostly focused on vaccines, but it''s also a good checkpoint for feeding. Your baby''s weight gain will be reviewed. Here are a few things worth asking while you have the pediatrician''s attention.',
  'Questions for the 2-month visit:

— Is growth on track? (Ask to see the growth curve percentile, not just today''s weight.)
— My baby seems to feed more often some days than others — is that normal? (Yes, usually.)
— Any concerns about my feeding method (nursing / pumping / combo) at this stage?
— If introducing a bottle: any signs of preference issues or feeding aversion to watch for?
— Is my baby''s development consistent with their feeding pattern?

At this visit, pediatricians are also screening for postpartum depression in mothers. If you''re struggling — with feeding, mood, or both — say so directly. You deserve support, and the pediatrician can connect you with resources. Sources: AAP 2022; ABM Protocol #3.',
  NULL,
  NULL,
  'AAP 2022; ABM Protocol #3',
  NULL,
  NULL,
  NULL
