INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-016',
  'Worried about supply? Let''s look at what''s actually happening',
  'Concerns about supply are one of the most common reasons moms stop breastfeeding earlier than they wanted to — and most of the time, the supply is actually fine. But some supply concerns are real and worth acting on. Let''s figure out which situation you''re in.',
  'The most reliable indicators of adequate supply are your baby''s output and weight — not how your breasts feel, how much you pump, or whether your baby "seems hungry." If your baby has 6+ wet diapers per day, 3+ stools (in the first 6 weeks), and is gaining appropriately at weight checks, your supply is almost certainly adequate.

Common reasons moms perceive low supply that aren''t actually supply issues: breasts feel softer after supply regulates (week 4–6), baby feeds more frequently during growth spurts, baby doesn''t sleep long stretches (not a supply problem), pump output feels low (pump output ≠ feeding output).

Actual supply challenges are less common but do exist. Risk factors include: previous breast surgery, hypoplastic breasts, delayed or infrequent feeding in the first weeks, retained placenta, hormonal conditions (PCOS, thyroid), significant bleeding or hemorrhage at delivery.

If you''re concerned: the most productive first step is a weighted feed or an IBCLC consultation — not adding formula without a plan, and not dramatically changing your feeding pattern based on how full or empty your breasts feel. Sources: ABM Protocol #2; ABM Protocol #9; "Making More Milk" (Marasco & West); LLLI.',
  'If your baby is not gaining weight appropriately, has fewer than 6 wet diapers per day after day 5, or seems lethargic and hard to rouse, contact your pediatrician the same day. These are the signs of actual insufficient intake, not perceived low supply.',
  NULL,
  'ABM Protocol #2; ABM Protocol #9; Marasco & West; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
