INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-018',
  'Mastitis: the warning signs every nursing mom should know now',
  'Mastitis — a breast infection — most commonly strikes in the first 2–6 weeks. Most moms who get it didn''t see it coming. Knowing the early signs can get you treated faster and back to feeding sooner. Want to know what to watch for?',
  'Mastitis is an inflammation of breast tissue, usually involving infection. It affects roughly 10% of breastfeeding moms, most commonly in weeks 2–6 but possible any time.

Early warning signs (don''t wait to act):
— A localized area of redness, warmth, or hardness in one breast
— Breast pain that feels different from normal fullness or engorgement
— Flu-like symptoms: fatigue, body aches, chills — these often precede the breast symptoms
— Fever above 100.4°F

What to do immediately:
— Keep feeding or pumping. Stopping makes mastitis worse. The breast needs to be emptied regularly.
— Rest (genuinely), stay hydrated, and take ibuprofen to manage inflammation and fever
— Apply warm compress before feeds to encourage milk flow
— Contact your OB or care provider the same day — most mastitis requires antibiotics

Mastitis is not a reason to stop breastfeeding. Milk is safe for the baby even during infection. Sources: ABM Protocol #36 (mastitis); ABM Protocol #2; LLLI.',
  'Mastitis requires same-day contact with your care provider. Untreated mastitis can progress to a breast abscess, which is much harder to treat. If you have fever, breast redness, and flu-like symptoms, call your OB today — don''t wait for a scheduled appointment.',
  NULL,
  'ABM Protocol #36; ABM Protocol #2; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
