INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-019',
  'Setting up your pump schedule: what matters most right now',
  'If you''re exclusively pumping, the schedule you set in the first few weeks directly affects your long-term supply. The timing and frequency matter more than duration right now. Here''s what to aim for.',
  'For exclusive pumpers, the first 6 weeks are the supply-establishment window — what you do now calibrates your baseline.

Frequency targets:
— Weeks 1–2: aim for 8–10 pump sessions per 24 hours. Yes, this includes at least one overnight session (typically around 3am) when prolactin is highest.
— Weeks 3–6: you can gradually reduce to 7–8 sessions as supply establishes, if output is where you want it.
— After week 6–8: many moms can reduce to 6–7 sessions once supply is regulated.

Duration: pump until the milk slows significantly, then 2 more minutes ("pumping to empty" matters more than watching a clock). Most sessions run 15–20 minutes on each side.

Single vs. double pump: double pumping is strongly preferred — it is more effective, takes half the time, and produces higher prolactin stimulation. If you only have a single pump, prioritize getting a double.

Hands-on pumping: using breast compression while pumping increases output by 25–50% in studies. Compress and massage one breast at a time while the pump runs.

Sources: ABM Protocol #32 (exclusive pumping); Hale''s Medications and Mothers'' Milk; published exclusive pumping literature.',
  NULL,
  NULL,
  'ABM Protocol #32; published EP literature',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
