INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-021',
  'Power pumping: what it is and when it actually helps',
  'Power pumping is a technique used to simulate cluster feeding — it sends a strong demand signal to your body to increase supply. It''s not magic, and it won''t help every situation. But if your supply has plateaued and your schedule and flange size are already dialed in, it''s worth understanding.',
  'Power pumping mimics the cluster feeding a nursing baby does during a growth spurt. One common protocol: pump 20 minutes, rest 10, pump 10, rest 10, pump 10 — 60 minutes total, replacing one regular pump session. Do this once per day for 3–7 consecutive days.

When power pumping helps: when supply has plateaued despite adequate session frequency and good flange fit; during or after illness or a significant reduction in sessions; after a period of stress or poor sleep that temporarily reduced output.

When it doesn''t help: if the underlying issue is anatomical (IGT, breast surgery) or hormonal, power pumping cannot override that. If flange size is wrong, power pumping with poor fit will cause pain and may not help output.

Before trying power pumping: confirm flange size is correct, confirm session frequency is at least 7–8 per 24 hours, and confirm you''re pumping to empty each session. These are more reliably effective than power pumping alone.

Sources: ABM Protocol #32; published exclusive pumping literature.',
  NULL,
  NULL,
  'ABM Protocol #32; published EP literature',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
