INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-023',
  'A note about your anatomy and supply — worth knowing early',
  'Based on what you shared about your breast anatomy, you may want to monitor your supply more closely in the first two weeks than the average mom. This doesn''t mean something will go wrong — but catching any concerns early makes them much more manageable.',
  'Both breast reduction surgery and hypoplastic/tubular breasts (Insufficient Glandular Tissue, or IGT) can affect the amount of milk-producing tissue available and the nerve pathways that drive the letdown reflex.

Brest reduction: the most common supply risk of any breast surgery. Outcomes depend heavily on the surgical technique — pedicle-based procedures that preserved the nipple attachment tend to have better outcomes than free nipple grafts. Some moms after reduction achieve full supply; many produce partial supply and successfully combo feed.

Hypoplastic breasts / IGT: the breast tissue present may simply produce less milk than a baby requires, and this often does not respond to increased feeding frequency or pumping the way typical low supply does. Signs that may suggest IGT include widely spaced breasts, disproportionately large areolas, a tubular breast shape, and minimal breast growth during pregnancy.

For both situations: the most important steps are (1) work with an IBCLC in the first week — don''t wait to see if supply is adequate; (2) monitor infant weight closely at the 5-day and 2-week checks; (3) have a combo feeding plan ready as a real and valid option, not a fallback.

Sources: ABM Protocol #2; ABM Protocol #9; Marasco & West "Making More Milk"; published IGT literature.',
  'If your baby is not regaining birth weight by day 10–12 or is showing signs of insufficient intake (fewer than 6 wet diapers, lethargic, not back to birth weight by 2 weeks), see an IBCLC and your pediatrician the same week — earlier than you might otherwise. Early intervention protects both supply and your baby''s growth.',
  NULL,
  'ABM Protocol #2; ABM Protocol #9; Marasco & West; published IGT literature',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
  in_app_message        = EXCLUDED.in_app_message,
