INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-024',
  'Getting a latch with flat or inverted nipples: a heads up before day one',
  'Getting a latch established with flat or inverted nipples can take a little more effort than average — but many moms do it successfully. Knowing a few techniques before you''re in the delivery room makes a real difference.',
  'Flat or inverted nipples make it harder for the baby to get a clear latch target, but they don''t prevent breastfeeding. Effective techniques:

Draw out the nipple before latching: use a pump on the lowest setting for 1–2 minutes immediately before a feed. This temporarily elongates the nipple and gives the baby something to latch onto. Hoffman''s exercises (gentle stretching) can also help, though evidence is mixed.

Breast sandwich: compress the breast tissue to create a more defined shape — like compressing a hamburger before taking a bite. This helps the baby get a deeper, more complete mouthful.

Nipple shield: a silicone shield worn over the nipple provides a firmer target for the baby to latch onto. Use with IBCLC guidance to confirm correct size and adequate milk transfer — shields can reduce milk flow if used incorrectly. They are a bridge tool, not a forever solution.

Positioning: the football hold gives you the most control over the baby''s head positioning and approach angle, which is especially useful with latch challenges.

For inverted nipples: the degree of inversion matters. Grade 1 (inverts but can be pulled out) responds well to the techniques above. Grade 3 (deeply inverted, does not evert) almost always benefits from IBCLC involvement from the first day — ideally a prenatal consultation.

Sources: ABM Protocol #2; ABM Protocol #11; LLLI latch guidance.',
  'If you have deeply inverted nipples (grade 3) or if latching is not improving by day 3–4 despite trying these techniques, request a lactation consult in the hospital before discharge. The earlier the intervention, the better the outcome.',
  NULL,
  'ABM Protocol #2; ABM Protocol #11; LLLI',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
