INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'AG-025',
  'A note about breastfeeding and your implants',
  'Most moms with breast implants breastfeed successfully, but the surgical history matters more than the implants themselves. Here''s what''s worth knowing — and what to watch for — in the first couple of weeks.',
  'Whether breast implants affect supply depends primarily on the surgical approach, not the implants themselves:

Incision type matters most: periareolar incisions (around the areola) carry the highest risk of disrupting milk ducts and the nerves responsible for letdown. Inframammary (breast fold) and axillary (armpit) incisions carry lower risk.

Implant placement: subglandular implants (over the muscle, directly under breast tissue) sit closest to glandular tissue and may compress it, potentially reducing functional tissue. Submuscular implants (under the pectoralis muscle) are further from glandular tissue and generally associated with lower breastfeeding impact.

What to do: tell your IBCLC and your baby''s pediatrician about your implant history before birth. Most will recommend closer supply and weight monitoring in the first 1–2 weeks rather than assuming everything is fine. Many moms with implants achieve full supply — but discovering a supply challenge at 3 weeks instead of 1 week costs valuable time.

You can find your surgical details (incision type, implant placement, implant type) in your plastic surgeon''s records if you don''t remember them.

Sources: ABM Protocol #2; published literature on breast implants and lactation (Semple et al.; Jewell et al.).',
  'Ask your IBCLC or pediatrician to monitor supply and weight gain more closely in the first two weeks if you have implants. Don''t wait for a weight gain concern to come up at the scheduled 2-week visit — request a weight check at day 5–7 if possible.',
  NULL,
  'ABM Protocol #2; published implants and lactation literature',
  NULL,
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
