INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'ML-011',
  'Second growth spurt survived',
  'Second growth spurt behind you. This one probably still surprised you — even though you''d been through it before — because each one is its own thing. But notice: you knew what it was. You knew it was temporary. You kept going. That''s different from week three. You''ve learned your baby.',
  NULL,
  NULL,
  'Second growth spurt, done. Getting better at reading what my baby needs.',
  NULL,
  'The growth-spurt-to-growth-spurt callback is intentional — it reinforces learning and progress across the journey, not just at this moment.',
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
