INSERT INTO companion_content
  (trigger_id, headline, in_app_message, learn_more, escalation_text,
   share_card, sources, design_note, in_app_message_path_b, in_app_message_path_c)
VALUES (
  'ML-017',
  'Kept supply through illness',
  'You were sick — really sick — and you kept feeding or pumping anyway. That is genuinely hard to do. When your body is using all its resources to fight an illness, keeping supply going takes everything you have left. Your supply made it through. So did you.',
  NULL,
  NULL,
  'Got sick. Kept going. Supply is still there.',
  NULL,
  'Keep this one short. When someone is coming out of illness, they don''t need a lot of words — they need acknowledgment that what they did was hard and it worked.',
  NULL,
  NULL
) ON CONFLICT (trigger_id) DO UPDATE SET
  headline              = EXCLUDED.headline,
